"use client"

import { useState } from "react"
import type { Candidate } from "@/types/candidate"
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Textarea } from "@/components/ui/textarea"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Button } from "@/components/ui/button"
import { useRouter } from "next/navigation"

type Props = {
  candidate: Candidate
}

export function CandidateDetailsForm({ candidate }: Props) {
  const router = useRouter()
  const [form, setForm] = useState({
    // Professional details
    seniority_level: candidate.seniority_level || "",
    reporting_manager: candidate.reporting_manager || "",
    preferred_location: candidate.preferred_location || "",
    skills: candidate.skills || "",
    experience: candidate.experience || "",
    expected_salary_currency: candidate.expected_salary_currency || "",
    expected_salary_range: candidate.expected_salary_range || "",

    // Preferences
    linkedin_profile: candidate.linkedin_profile || "",
    portfolio: candidate.portfolio || "",
    preferred_role: candidate.preferred_role || "",
    work_permit_status: candidate.work_permit_status || "",
    employment_type: candidate.employment_type || "",
    work_mode: candidate.work_mode || "",
    references: candidate.references || "",
    notice_period: candidate.notice_period || "",
    actively_seeking_toggle: candidate.actively_seeking_toggle || "",
  })
  const [isSaving, setIsSaving] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [success, setSuccess] = useState<string | null>(null)

  const handleChange = (field: keyof typeof form, value: string) => {
    setForm((prev) => ({ ...prev, [field]: value }))
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!candidate.id) return

    setIsSaving(true)
    setError(null)
    setSuccess(null)

    try {
      const res = await fetch(`/api/candidates/${candidate.id}`, {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(form),
      })

      const data = await res.json()

      if (!res.ok) {
        throw new Error(data.error || "Failed to update candidate")
      }

      setSuccess("Candidate details updated.")
      // Refresh the page data
      router.refresh()
    } catch (err) {
      setError(err instanceof Error ? err.message : "Something went wrong")
    } finally {
      setIsSaving(false)
    }
  }

  return (
    <Card className="border-2">
      <CardHeader>
        <CardTitle>Edit Candidate Details (excluding basic info)</CardTitle>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label>Seniority level</Label>
              <Input
                value={form.seniority_level}
                onChange={(e) => handleChange("seniority_level", e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label>Reporting manager</Label>
              <Input
                value={form.reporting_manager}
                onChange={(e) => handleChange("reporting_manager", e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label>Preferred location</Label>
              <Input
                value={form.preferred_location}
                onChange={(e) => handleChange("preferred_location", e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label>Experience</Label>
              <Input
                value={form.experience}
                onChange={(e) => handleChange("experience", e.target.value)}
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label>Skills (comma separated)</Label>
            <Textarea
              value={form.skills}
              onChange={(e) => handleChange("skills", e.target.value)}
              rows={3}
            />
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label>Expected salary currency</Label>
              <Input
                value={form.expected_salary_currency}
                onChange={(e) => handleChange("expected_salary_currency", e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label>Expected salary range</Label>
              <Input
                value={form.expected_salary_range}
                onChange={(e) => handleChange("expected_salary_range", e.target.value)}
              />
            </div>
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label>LinkedIn profile</Label>
              <Input
                value={form.linkedin_profile}
                onChange={(e) => handleChange("linkedin_profile", e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label>Preferred role</Label>
              <Input
                value={form.preferred_role}
                onChange={(e) => handleChange("preferred_role", e.target.value)}
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label>Portfolio / work showcase</Label>
            <Textarea
              value={form.portfolio}
              onChange={(e) => handleChange("portfolio", e.target.value)}
              rows={3}
            />
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label>Work permit status</Label>
              <Input
                value={form.work_permit_status}
                onChange={(e) => handleChange("work_permit_status", e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label>Employment type</Label>
              <Select
                value={form.employment_type || ""}
                onValueChange={(val) => handleChange("employment_type", val)}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select type" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="Permanent">Permanent</SelectItem>
                  <SelectItem value="Contract">Contract</SelectItem>
                  <SelectItem value="Freelance">Freelance</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label>Work mode</Label>
              <Select
                value={form.work_mode || ""}
                onValueChange={(val) => handleChange("work_mode", val)}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select mode" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="Onsite">Onsite</SelectItem>
                  <SelectItem value="Hybrid">Hybrid</SelectItem>
                  <SelectItem value="Remote">Remote</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Notice period</Label>
              <Input
                value={form.notice_period}
                onChange={(e) => handleChange("notice_period", e.target.value)}
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label>Actively seeking status</Label>
            <Select
              value={form.actively_seeking_toggle || ""}
              onValueChange={(val) => handleChange("actively_seeking_toggle", val)}
            >
              <SelectTrigger>
                <SelectValue placeholder="Select status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="Actively Seeking">Actively Seeking</SelectItem>
                <SelectItem value="Passive">Passive</SelectItem>
                <SelectItem value="Not Looking">Not Looking</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label>References</Label>
            <Textarea
              value={form.references}
              onChange={(e) => handleChange("references", e.target.value)}
              rows={3}
            />
          </div>

          {error && <p className="text-sm text-red-500">{error}</p>}
          {success && <p className="text-sm text-green-600">{success}</p>}

          <Button type="submit" disabled={isSaving}>
            {isSaving ? "Saving..." : "Save changes"}
          </Button>
        </form>
      </CardContent>
    </Card>
  )
}


